import { useEffect, useMemo, useState } from "react";
import {
  MapContainer,
  TileLayer,
  Marker,
  Popup
} from "react-leaflet";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  ResponsiveContainer
} from "recharts";

import L from "leaflet";
import "leaflet/dist/leaflet.css";
import markerIcon2x from "leaflet/dist/images/marker-icon-2x.png";
import markerIcon from "leaflet/dist/images/marker-icon.png";
import markerShadow from "leaflet/dist/images/marker-shadow.png";

delete L.Icon.Default.prototype._getIconUrl;

L.Icon.Default.mergeOptions({
  iconRetinaUrl: markerIcon2x,
  iconUrl: markerIcon,
  shadowUrl: markerShadow
});

function runEnergyDecisionEngine(homes, weather, gridLoad) {
  const weatherMultiplier = getWeatherMultiplier(weather);

  const analyzedHomes = homes.map((home) => {
    const generatedPower = Number(home.generatedPower || 0);
    const consumedPower = Number(home.consumedPower || 0);
    const batteryLevel = Number(home.batteryLevel || 0);

    const adjustedGeneratedPower = generatedPower * weatherMultiplier;
    const netEnergy = adjustedGeneratedPower - consumedPower;

    let aiRole = "BALANCED";
    let aiDecision = "Maintain current energy usage";

    if (netEnergy > 1.5 && batteryLevel > 60) {
      aiRole = "SELLER";
      aiDecision = "Sell surplus energy to nearby buyers";
    } else if (netEnergy > 0 && batteryLevel <= 60) {
      aiRole = "STORAGE";
      aiDecision = "Store surplus energy in battery";
    } else if (netEnergy < -1) {
      aiRole = "BUYER";
      aiDecision = "Buy renewable energy from local sellers";
    }

    return {
      ...home,
      adjustedGeneratedPower: Number(adjustedGeneratedPower.toFixed(2)),
      netEnergy: Number(netEnergy.toFixed(2)),
      aiRole,
      aiDecision
    };
  });

  const sellers = analyzedHomes.filter((home) => home.aiRole === "SELLER");
  const buyers = analyzedHomes.filter((home) => home.aiRole === "BUYER");

  const energyPrice = calculateEnergyPrice(
    buyers.length,
    sellers.length,
    gridLoad
  );

  const trades = createTrades(sellers, buyers, energyPrice);

  const totalGenerated = analyzedHomes.reduce(
    (sum, home) => sum + home.adjustedGeneratedPower,
    0
  );

  const totalConsumed = analyzedHomes.reduce(
    (sum, home) => sum + Number(home.consumedPower || 0),
    0
  );

  const carbonSaved = trades.reduce(
    (sum, trade) => sum + trade.energy * 0.7,
    0
  );

  const renewablePercentage =
    totalConsumed > 0 ? (totalGenerated / totalConsumed) * 100 : 0;

  const blackoutPrevented = gridLoad > 85 && sellers.length > 0;

  return {
    homes: analyzedHomes,
    sellers,
    buyers,
    trades,
    energyPrice,
    totalGenerated: Number(totalGenerated.toFixed(2)),
    totalConsumed: Number(totalConsumed.toFixed(2)),
    carbonSaved: Number(carbonSaved.toFixed(2)),
    renewablePercentage: Number(renewablePercentage.toFixed(1)),
    blackoutPrevented,
    gridStatus: blackoutPrevented
      ? "AI PREVENTED OVERLOAD"
      : totalGenerated >= totalConsumed
      ? "GRID OPERATING EFFICIENTLY"
      : "HIGH GRID LOAD DETECTED"
  };
}

function getWeatherMultiplier(weather) {
  if (weather === "Sunny") return 1.2;
  if (weather === "Cloudy") return 0.8;
  if (weather === "Rainy") return 0.55;
  return 1;
}

function calculateEnergyPrice(buyerCount, sellerCount, gridLoad) {
  let price = 6;

  if (buyerCount > sellerCount) price += 2;
  if (sellerCount > buyerCount) price -= 1;
  if (gridLoad > 80) price += 3;

  return Math.max(price, 3);
}

function createTrades(sellers, buyers, price) {
  return buyers
    .map((buyer, index) => {
      const seller = sellers[index % sellers.length];

      if (!seller) return null;

      const energy = Math.min(
        Math.abs(Number(buyer.netEnergy || 0)),
        Number(seller.netEnergy || 0)
      );

      if (energy <= 0) return null;

      return {
        id: `TX-${Date.now()}-${index}`,
        from: seller.house,
        to: buyer.house,
        energy: Number(energy.toFixed(2)),
        price,
        totalCost: Number((energy * price).toFixed(2)),
        hash: Math.random().toString(16).slice(2, 12).toUpperCase(),
        reason: `${seller.house} sold ${energy.toFixed(
          2
        )} kWh to ${buyer.house} because seller had surplus energy and buyer had energy shortage.`
      };
    })
    .filter(Boolean);
}

function App() {
  const [homes, setHomes] = useState([]);
  const [chartData, setChartData] = useState([]);
  const [predictions, setPredictions] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [weather, setWeather] = useState("Sunny");
  const [gridLoad, setGridLoad] = useState(72);

  const engine = useMemo(
    () => runEnergyDecisionEngine(homes, weather, gridLoad),
    [homes, weather, gridLoad]
  );

  useEffect(() => {
    const fetchEnergy = () => {
      fetch("http://localhost:5000/energy")
        .then((res) => res.json())
        .then((data) => {
          const incomingHomes = data.homes || [];

          setHomes(incomingHomes);
          setPredictions(data.predictions || []);
          setAlerts(data.alerts || []);

          const temporaryEngine = runEnergyDecisionEngine(
            incomingHomes,
            weather,
            gridLoad
          );

          setChartData((prev) => [
            ...prev.slice(-9),
            {
              time: new Date().toLocaleTimeString(),
              generated: temporaryEngine.totalGenerated,
              consumed: temporaryEngine.totalConsumed
            }
          ]);
        })
        .catch((error) => {
          console.error("Energy API error:", error);
        });
    };

    fetchEnergy();

    const interval = setInterval(fetchEnergy, 3000);

    return () => clearInterval(interval);
  }, [weather, gridLoad]);

  const totalHomes = engine.homes.length;
  const activeSellers = engine.sellers.length;
  const activeBuyers = engine.buyers.length;

  return (
    <div className="min-h-screen bg-black text-white p-8">
      <h1 className="text-5xl font-bold text-green-400 mb-10 text-center">
        OpenGreenGrid Dashboard
      </h1>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
        <div className="bg-gray-900 border border-cyan-400 rounded-2xl p-6 text-center shadow-lg">
          <h2 className="text-2xl font-bold text-cyan-300">Total Homes</h2>
          <p className="text-5xl font-bold mt-4">{totalHomes}</p>
        </div>

        <div className="bg-gray-900 border border-green-400 rounded-2xl p-6 text-center shadow-lg">
          <h2 className="text-2xl font-bold text-green-300">
            AI Energy Sellers
          </h2>
          <p className="text-5xl font-bold mt-4">{activeSellers}</p>
        </div>

        <div className="bg-gray-900 border border-red-400 rounded-2xl p-6 text-center shadow-lg">
          <h2 className="text-2xl font-bold text-red-300">
            AI Energy Buyers
          </h2>
          <p className="text-5xl font-bold mt-4">{activeBuyers}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-12">
        <div className="bg-gray-900 border border-yellow-400 rounded-2xl p-6 shadow-lg">
          <h2 className="text-xl font-bold text-yellow-300">Weather Impact</h2>
          <select
            value={weather}
            onChange={(event) => setWeather(event.target.value)}
            className="mt-4 w-full bg-black border border-yellow-400 p-3 rounded-xl"
          >
            <option>Sunny</option>
            <option>Cloudy</option>
            <option>Rainy</option>
          </select>
        </div>

        <div className="bg-gray-900 border border-blue-400 rounded-2xl p-6 shadow-lg">
          <h2 className="text-xl font-bold text-blue-300">Grid Load</h2>
          <input
            type="range"
            min="30"
            max="100"
            value={gridLoad}
            onChange={(event) => setGridLoad(Number(event.target.value))}
            className="w-full mt-5"
          />
          <p className="text-3xl font-bold mt-3">{gridLoad}%</p>
        </div>

        <div className="bg-gray-900 border border-emerald-400 rounded-2xl p-6 shadow-lg">
          <h2 className="text-xl font-bold text-emerald-300">Carbon Saved</h2>
          <p className="text-4xl font-bold mt-4">{engine.carbonSaved} kg</p>
        </div>

        <div className="bg-gray-900 border border-pink-400 rounded-2xl p-6 shadow-lg">
          <h2 className="text-xl font-bold text-pink-300">Energy Price</h2>
          <p className="text-4xl font-bold mt-4">₹{engine.energyPrice}/kWh</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {engine.homes.map((home, index) => (
          <div
            key={index}
            className="bg-gray-900 border border-green-500 rounded-2xl p-6 shadow-lg hover:scale-105 transition duration-300"
          >
            <h2 className="text-3xl font-semibold mb-4 text-green-300">
              {home.house}
            </h2>

            <p className="text-lg mb-2">
              Generated Power:
              <span className="text-green-400 font-bold">
                {" "}
                {home.generatedPower} kWh
              </span>
            </p>

            <p className="text-lg mb-2">
              Weather Adjusted:
              <span className="text-cyan-400 font-bold">
                {" "}
                {home.adjustedGeneratedPower} kWh
              </span>
            </p>

            <p className="text-lg mb-2">
              Consumed Power:
              <span className="text-yellow-400 font-bold">
                {" "}
                {home.consumedPower} kWh
              </span>
            </p>

            <p className="text-lg mb-2">
              Battery Level:
              <span className="text-blue-400 font-bold">
                {" "}
                {home.batteryLevel}%
              </span>
            </p>

            <p className="text-lg mb-2">
              Carbon Saved:
              <span className="text-emerald-400 font-bold">
                {" "}
                {home.carbonSaved} kg
              </span>
            </p>

            <p className="text-lg mb-4">
              Efficiency Score:
              <span className="text-pink-400 font-bold">
                {" "}
                {home.efficiencyScore}%
              </span>
            </p>

            <div
              className={`p-3 rounded-xl text-center font-bold text-lg ${
                home.status === "SELLING ENERGY"
                  ? "bg-green-600"
                  : home.status === "BUYING ENERGY"
                  ? "bg-red-600"
                  : "bg-yellow-500 text-black"
              }`}
            >
              {home.status}
            </div>

            <div className="mt-4 bg-black border border-cyan-500 rounded-xl p-4">
              <p className="text-cyan-300 font-bold">AI Role: {home.aiRole}</p>
              <p className="text-sm mt-2">{home.aiDecision}</p>
              <p className="text-sm mt-2">
                Net Energy:{" "}
                <span
                  className={
                    home.netEnergy >= 0 ? "text-green-400" : "text-red-400"
                  }
                >
                  {home.netEnergy} kWh
                </span>
              </p>
            </div>
          </div>
        ))}
      </div>

      <div className="mt-12">
        <h2 className="text-4xl font-bold text-cyan-400 mb-6">
          Autonomous DeFi Energy Trades
        </h2>

        {engine.trades.length === 0 ? (
          <div className="bg-gray-900 p-4 rounded-xl text-gray-400">
            No AI trades currently
          </div>
        ) : (
          engine.trades.map((trade, index) => (
            <div
              key={index}
              className="bg-cyan-900 border border-cyan-400 p-5 rounded-xl mb-4 shadow-lg"
            >
              <p className="text-xl">
                <span className="font-bold">{trade.from}</span> sold{" "}
                <span className="text-cyan-300 font-bold">
                  {trade.energy} kWh
                </span>{" "}
                to <span className="font-bold">{trade.to}</span>
              </p>

              <p className="text-cyan-300 mt-2">
                Price: ₹{trade.price}/kWh | Total: ₹{trade.totalCost}
              </p>

              <p className="text-sm mt-2">Blockchain Hash: {trade.hash}</p>

              <p className="text-sm mt-2 text-gray-200">
                AI Reason: {trade.reason}
              </p>
            </div>
          ))
        )}
      </div>

      <div className="mt-12">
        <h2 className="text-4xl font-bold text-purple-400 mb-6">
          Real-Time Energy Analytics
        </h2>

        <div className="bg-gray-900 p-6 rounded-2xl border border-purple-500">
          <ResponsiveContainer width="100%" height={400}>
            <LineChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="time" />
              <YAxis />
              <Tooltip />
              <Line
                type="monotone"
                dataKey="generated"
                stroke="#00ff88"
                strokeWidth={3}
              />
              <Line
                type="monotone"
                dataKey="consumed"
                stroke="#ff4444"
                strokeWidth={3}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="mt-12">
        <h2 className="text-4xl font-bold text-green-400 mb-6">
          Smart City Energy Map
        </h2>

        <div className="rounded-2xl overflow-hidden border border-green-500">
          <MapContainer
            center={[28.6139, 77.209]}
            zoom={12}
            style={{ height: "500px", width: "100%" }}
          >
            <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

            {engine.homes.map((home, index) => (
              <Marker
                key={index}
                position={[home.latitude, home.longitude]}
              >
                <Popup>
                  <div>
                    <h2>{home.house}</h2>
                    <p>Generated: {home.adjustedGeneratedPower} kWh</p>
                    <p>Consumed: {home.consumedPower} kWh</p>
                    <p>Battery: {home.batteryLevel}%</p>
                    <p>AI Role: {home.aiRole}</p>
                    <p>Decision: {home.aiDecision}</p>
                  </div>
                </Popup>
              </Marker>
            ))}
          </MapContainer>
        </div>
      </div>

      <div className="mt-12">
        <h2 className="text-4xl font-bold text-blue-400 mb-6">
          Smart Grid Health
        </h2>

        <div className="bg-gray-900 border border-blue-500 rounded-2xl p-8 shadow-lg">
          <p className="text-2xl mb-4">
            Total Generated Energy:
            <span className="text-green-400 font-bold">
              {" "}
              {engine.totalGenerated} kWh
            </span>
          </p>

          <p className="text-2xl mb-4">
            Total Consumed Energy:
            <span className="text-yellow-400 font-bold">
              {" "}
              {engine.totalConsumed} kWh
            </span>
          </p>

          <p className="text-2xl mb-4">
            Renewable Percentage:
            <span className="text-emerald-400 font-bold">
              {" "}
              {engine.renewablePercentage}%
            </span>
          </p>

          <p className="text-2xl">
            Grid Status:
            <span className="text-cyan-400 font-bold">
              {" "}
              {engine.gridStatus}
            </span>
          </p>

          {engine.blackoutPrevented && (
            <p className="text-green-400 text-xl mt-4 font-bold">
              AI rerouted surplus renewable energy and prevented overload.
            </p>
          )}
        </div>
      </div>

      <div className="mt-12">
        <h2 className="text-4xl font-bold text-orange-400 mb-6">
          AI Prediction Engine
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {predictions.map((item, index) => (
            <div
              key={index}
              className="bg-gray-900 border border-orange-500 rounded-2xl p-6 shadow-lg"
            >
              <h3 className="text-2xl font-bold text-orange-300 mb-4">
                {item.house}
              </h3>

              <p className="text-lg font-semibold">{item.prediction}</p>
            </div>
          ))}
        </div>
      </div>

      <div className="mt-12">
        <h2 className="text-4xl font-bold text-red-400 mb-6">
          Smart Grid Alerts
        </h2>

        {alerts.length === 0 ? (
          <div className="bg-gray-900 p-5 rounded-xl text-gray-400">
            No critical alerts detected
          </div>
        ) : (
          alerts.map((alert, index) => (
            <div
              key={index}
              className="bg-red-900 border border-red-500 p-5 rounded-xl mb-4 shadow-lg animate-pulse"
            >
              <p className="text-xl font-bold">{alert.house}</p>
              <p className="text-lg mt-2">{alert.message}</p>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default App;
